import React, { useState, useEffect } from 'react';
import { partnerService } from '../services/api';
import { ShoppingCart, Filter, Copy, Check } from 'lucide-react';
import './PartnerSales.css';

function PartnerSales() {
  const [sales, setSales] = useState([]);
  const [filteredSales, setFilteredSales] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [statusFilter, setStatusFilter] = useState('All');
  const [copiedKey, setCopiedKey] = useState(null);

  useEffect(() => {
    loadSales();
  }, []);

  useEffect(() => {
    filterSales();
  }, [sales, statusFilter]);

  const loadSales = async () => {
    try {
      setLoading(true);
      const response = await partnerService.getSales();
      setSales(response.data);
      setError('');
    } catch (err) {
      console.error('Load sales error:', err);
      setError('Failed to load sales');
    } finally {
      setLoading(false);
    }
  };

  const filterSales = () => {
    if (statusFilter === 'All') {
      setFilteredSales(sales);
    } else {
      setFilteredSales(sales.filter(sale => sale.paymentStatus === statusFilter));
    }
  };

  const copyLicenseKey = (licenseKey, saleId) => {
    navigator.clipboard.writeText(licenseKey);
    setCopiedKey(saleId);
    setTimeout(() => setCopiedKey(null), 2000);
  };

  const formatCurrency = (amount) => {
    return `₹${amount.toLocaleString('en-IN', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}`;
  };

  const formatDate = (dateString) => {
    return new Date(dateString).toLocaleDateString('en-IN', {
      year: 'numeric',
      month: 'short',
      day: 'numeric',
      hour: '2-digit',
      minute: '2-digit'
    });
  };

  const totalRevenue = filteredSales.reduce((sum, sale) => sum + sale.saleAmount, 0);
  const totalCommission = filteredSales.reduce((sum, sale) => sum + sale.commissionAmount, 0);
  const paidCommission = filteredSales
    .filter(sale => sale.paymentStatus === 'Completed')
    .reduce((sum, sale) => sum + sale.commissionAmount, 0);

  if (loading) {
    return <div className="loading">Loading sales...</div>;
  }

  return (
    <div className="partner-sales-page">
      <div className="page-header">
        <div>
          <h1>My Sales</h1>
          <p>Track all your sales and commissions</p>
        </div>
      </div>

      {error && <div className="error-message">{error}</div>}

      {/* Summary Cards */}
      <div className="sales-summary">
        <div className="summary-card">
          <h3>Total Sales</h3>
          <p className="summary-value">{filteredSales.length}</p>
        </div>
        <div className="summary-card">
          <h3>Total Revenue</h3>
          <p className="summary-value">{formatCurrency(totalRevenue)}</p>
        </div>
        <div className="summary-card">
          <h3>Total Commission</h3>
          <p className="summary-value">{formatCurrency(totalCommission)}</p>
        </div>
        <div className="summary-card">
          <h3>Paid Commission</h3>
          <p className="summary-value success">{formatCurrency(paidCommission)}</p>
        </div>
      </div>

      {/* Filters */}
      <div className="filters-bar">
        <div className="filter-group">
          <Filter size={20} />
          <label>Status:</label>
          <select value={statusFilter} onChange={(e) => setStatusFilter(e.target.value)}>
            <option value="All">All</option>
            <option value="Pending">Pending</option>
            <option value="Completed">Completed</option>
            <option value="Failed">Failed</option>
          </select>
        </div>
      </div>

      {filteredSales.length === 0 ? (
        <div className="empty-state">
          <ShoppingCart size={64} color="#ccc" />
          <h3>No Sales Found</h3>
          <p>
            {statusFilter === 'All'
              ? 'You haven\'t made any sales yet. Start selling products to earn commission!'
              : `No ${statusFilter.toLowerCase()} sales found.`}
          </p>
        </div>
      ) : (
        <div className="table-container">
          <table className="data-table">
            <thead>
              <tr>
                <th>Date</th>
                <th>Product</th>
                <th>Buyer</th>
                <th>Amount</th>
                <th>Commission</th>
                <th>Status</th>
                <th>License Key</th>
                <th>Notes</th>
              </tr>
            </thead>
            <tbody>
              {filteredSales.map((sale) => (
                <tr key={sale.saleId}>
                  <td>{formatDate(sale.saleDate)}</td>
                  <td className="product-name">{sale.productName}</td>
                  <td>
                    <div>
                      <div className="buyer-name">{sale.buyerName}</div>
                      <div className="buyer-email">{sale.buyerEmail}</div>
                      {sale.buyerCompany && (
                        <div className="buyer-company">{sale.buyerCompany}</div>
                      )}
                    </div>
                  </td>
                  <td className="amount">{formatCurrency(sale.saleAmount)}</td>
                  <td className="amount commission">{formatCurrency(sale.commissionAmount)}</td>
                  <td>
                    <span className={`status-badge status-${sale.paymentStatus.toLowerCase()}`}>
                      {sale.paymentStatus}
                    </span>
                  </td>
                  <td>
                    <div className="license-key-container">
                      <code className="license-key">{sale.licenseKey}</code>
                      <button
                        className="btn-copy"
                        onClick={() => copyLicenseKey(sale.licenseKey, sale.saleId)}
                        title="Copy license key"
                      >
                        {copiedKey === sale.saleId ? (
                          <Check size={16} color="#4caf50" />
                        ) : (
                          <Copy size={16} />
                        )}
                      </button>
                    </div>
                  </td>
                  <td className="notes-cell">{sale.notes || '-'}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
}

export default PartnerSales;
